svg.script:
function prepareSVG() {
	var root = document.getElementById('_0');
	document.getElementById('_0_0a').onclick = expandAll;
	document.getElementById('_0_0_0b').onclick = collapseAll;
}


function expandAll() {
	var indexes = [0, 0];
	var id;
	var y = delta_y;
	var ymins = [y];
	var ymaxs = [y];
	var el;
	while (true) {
		id = '_' + indexes.join('_');
		if (!ids.includes(id)) {
			indexes.splice(-1, 1);
			ymin = ymins.splice(-1, 1);
			ymax = ymaxs.splice(-1, 1);
			if (indexes.length == 1) {
				break;
			}
			id = '_' + indexes.join('_');

			el = document.getElementById(id+'_0d');
			if (el != null) {
				adjustY_verticalLine(el, ymin, ymax);
			}

			indexes[indexes.length-1] += 1;
			id = '_' + indexes.join('_');
			if (ids.includes(id)) {
				y += delta_y;
				ymaxs[ymaxs.length-1] = y;
			}
		} else {
			el = document.getElementById(id);
			removeAllHidden(el);
			adjustY(el, y);
			for (var letter of "abcdef".split('')) {
				el = document.getElementById(id + letter);
				if (el != null) {
					removeAllHidden(el);
					adjustY(el, y);
				}
			}
			el = document.getElementById(id);
			if (el.classList.contains('co')) {
				el.classList.remove('co');
				el.classList.add('ex');
			}
			indexes = indexes.concat(0);
			ymins = ymins.concat(y);
			ymaxs = ymaxs.concat(y);
		}
	}
}


function collapseAll() {
	var indexes = [0, 0];
	var y = delta_y;
	var ymins = [y, y];
	var id;
	var el;
	var el_d;
	var numberHidden = 0;
	while (true) {
		id = '_' + indexes.join('_');
		if (!ids.includes(id)) {
			indexes.splice(-1, 1);
			ymin = ymins.splice(-1, 1)[0];
			if (indexes.length == 1) {
				break;
			}
			id = '_' + indexes.join('_');
			el_d = document.getElementById(id+'_0d');
			if (el_d != null) {
				y -= delta_y;
			} else if (ids.includes(id+'_0') && !ids.includes(id+'_1')) {
				y -= delta_y;
			}
			if (el_d != null) {
				adjustY_verticalLine(el_d, ymin, y);
			}
			el = document.getElementById(id);
			
			if (el.classList.contains('se')) {
				numberHidden--;
				y = ymin;
			}
			indexes[indexes.length-1] += 1;
			y += delta_y;
		} else {
			el = document.getElementById(id);
			adjustHidden(el, numberHidden);
			adjustY(el, y);
			for (var letter of "abcdef".split('')) {
				el = document.getElementById(id + letter);
				if (el != null) {
					adjustHidden(el, numberHidden);
					adjustY(el, y);
				}
			}
			el = document.getElementById(id);
			if (el.classList.contains('ex')) {
				el.classList.remove('ex');
				el.classList.add('co');
			}
			if (el.classList.contains('se')) {
				numberHidden++;
			}
			indexes = indexes.concat(0);
			ymins = ymins.concat(y);
		}
	}
}


function removeAllHidden(el) {
	if (el.classList.contains('hd')) {
		el.classList.remove('hd');
		var i = 1;
		while (el.classList.contains('hd'+i)) {
			el.classList.remove('hd'+i);
			i++;
		}
	}
}


function adjustHidden(el, numberHidden) {
	var alreadyHidden = 0;
	if (el.classList.contains('hd')) {
		alreadyHidden = 1;
		while (el.classList.contains('hd'+alreadyHidden)) {
			alreadyHidden++;
		}
	}
	for (var i=alreadyHidden; i<numberHidden; i++) {
		addHidden(el);
	}
}


function adjustY(el, y) {
	// elements and horizontal lines
	if (el.tagName === 'line') {
		el.setAttribute('y1', y);
		el.setAttribute('y2', y);
	} else {
		el.transform.baseVal[0].matrix.f = y;
	}
}


function adjustY_verticalLine(el, ymin, ymax) {
	el.setAttribute('y1', ymin);
	el.setAttribute('y2', ymax);
}


function addHidden(el) {
	if (!el.classList.contains('hd')) {
		el.classList.add('hd');
	} else {
		var i = 1;
		while (el.classList.contains('hd'+i)) {
			i++;
		}
		el.classList.add('hd'+i);
	}
}


function removeHidden(el) {
	if (!el.classList.contains('hd1')) {
		el.classList.remove('hd');
	} else {
		var i = 1;
		while (el.classList.contains('hd'+i)) {
			i++;
		}
		el.classList.remove('hd'+(i-1));
	}
}


function t(sel) {
	/* toggle */
	hiding = sel.classList.contains('ex');
	sel.classList.toggle('ex');
	sel.classList.toggle('co');

	y_start = sel.transform.baseVal[0].matrix.f;
	y_end = y_start
	
	var sel_id = sel.getAttribute('id')
	var id;
	var el;
	var indexes = [0]
	while (true) {
		id = sel_id + '_' + indexes.join('_');
		if (!ids.includes(id)) {
			indexes.splice(-1, 1);
			if (indexes.length == 0) {
				break;
			}
			indexes[indexes.length-1] += 1;
		} else {
			el = document.getElementById(id);
			if (hiding) {
				if (!el.classList.contains('hd')) {
					y_end = Math.max(y_end, el.transform.baseVal[0].matrix.f);
				}
				addHidden(el);
				for (letter of 'abcdef'.split('')) {
					el = document.getElementById(id+letter);
					if (el != null) {
						addHidden(el);
					}
				}
			} else {
				removeHidden(el);
				if (!el.classList.contains('hd')) {
					y_end = Math.max(y_end, el.transform.baseVal[0].matrix.f);
				}
				for (letter of 'abcdef'.split('')) {
					el = document.getElementById(id+letter);
					if (el != null) {
						removeHidden(el);
					}
				}
			}
			indexes = indexes.concat(0);
		}
	}
	
	dy = y_start - y_end;
	if (!hiding) {
		dy = -dy;
	}
	indexes = sel_id.split('_').map(Number);
	indexes.splice(0, 1);
	var root_indexes = indexes.slice();
	var root_id = '';
	
	indexes[indexes.length-1] += 1;
	id = '_' + indexes.join('_');
	if (!ids.includes(id)) {
		indexes.splice(-1, 1);
		if (indexes.length == 0) {
			return;
		}
		indexes[indexes.length-1] += 1;
	}
	while (indexes.length > 1) {
		id = '_' + indexes.join('_');
		if (!ids.includes(id)) {
			indexes.splice(-1, 1);
			id = '_' + indexes.join('_');
			root_id = '_' + root_indexes.slice(0, indexes.length).join('_');
			if (root_id === id && ids.includes(root_id+'_'+(root_indexes[indexes.length]+1))) {
				el = document.getElementById(id+'_0d');
				if (el != null) {
					el.setAttribute('y2', parseFloat(el.getAttribute('y2')) + dy);
				}
			}
			indexes[indexes.length-1] += 1;
		} else {
			translate(document.getElementById(id), dy);			
			for (var letter of 'abcdef'.split('')) {
				el = document.getElementById(id+letter);
				if (el != null) {
					translate(el, dy);
				}
			}
			indexes = indexes.concat(0);
		}
	}
}


function td(sel) {
	/* toggleDescendants */
	window.event.preventDefault();
	var expand_all_descendants = false;
	if (sel.classList.contains("co")) {
		sel.onclick();
		expand_all_descendants = true;
	}
	var sel_id = sel.getAttribute('id')
	var indexes = [0];
	var id;
	var el;
	while (true) {
		id = sel_id + '_' + indexes.join('_');
		if (!ids.includes(id)) {
			indexes.splice(-1, 1);
			if (indexes.length == 0) {
				break;
			}
			indexes[indexes.length-1] += 1;
		} else {
			el = document.getElementById(id);
			if (el.classList.contains('se')) {
				if (expand_all_descendants) {
					if (el.classList.contains('co')) {
						el.onclick();
					}
				} else {
					el.onclick();
				}
				indexes[indexes.length-1] += 1;
				id = sel_id + '_' + indexes.join('_');
				if (ids.includes(id)) {
					continue;
				}
				indexes.splice(-1, 1);
				if (indexes.length == 0) {
					break;
				}
				indexes[indexes.length-1] += 1;
			} else {
				indexes = indexes.concat(0);
			}
		}
	}
	return false;
}


function translate(el, dy) {
	if (el.tagName === 'line') {
		el.setAttribute('y1', parseFloat(el.getAttribute('y1')) + dy);
		el.setAttribute('y2', parseFloat(el.getAttribute('y2')) + dy);
	} else {
		el.transform.baseVal[0].matrix.f += dy;
	}
}
const ids=["_0","_0_0","_0_0_0","_0_0_0_0","_0_0_0_0_0","_0_0_0_0_0_0","_0_0_0_0_0_0_0","_0_0_0_0_0_0_0_0","_0_0_0_0_0_0_0_0_0","_0_0_0_0_0_0_0_0_1","_0_0_0_0_0_0_0_0_2","_0_0_0_0_0_0_0_0_3","_0_0_0_0_0_0_0_0_3_0","_0_0_0_0_0_0_0_0_3_0_0","_0_0_0_0_0_0_0_0_3_0_1","_0_0_0_0_0_0_0_0_4","_0_0_0_0_0_0_0_0_4_0","_0_0_0_0_0_0_0_0_4_0_0","_0_0_0_0_0_0_0_0_4_0_0_0","_0_0_0_0_0_0_0_0_4_0_0_0_0","_0_0_0_0_0_0_0_0_4_0_0_0_1","_0_0_0_0_0_0_0_0_4_0_1","_0_0_0_0_0_0_0_0_4_0_2","_0_0_0_0_0_0_0_0_4_0_3","_0_0_0_0_0_0_0_0_4_0_4","_0_0_0_0_0_0_0_0_4_0_5","_0_0_0_0_0_0_0_0_4_0_6","_0_0_0_0_0_0_0_0_4_0_7","_0_0_0_0_0_0_0_0_4_0_8","_0_0_0_0_0_0_0_0_4_0_9","_0_0_0_0_0_0_0_0_5","_0_0_0_0_0_0_0_0_6","_0_0_0_0_0_0_0_0_6_0","_0_0_0_0_0_0_0_0_6_0_0","_0_0_0_0_0_0_0_0_6_0_1","_0_0_0_0_0_0_0_0_7","_0_0_0_0_0_0_0_0_8","_0_0_0_0_0_0_0_0_8_0","_0_0_0_0_0_0_0_0_8_0_0","_0_0_0_0_0_0_0_0_8_0_1","_0_0_0_0_0_0_0_0_8_0_2","_0_0_0_0_0_0_0_0_8_0_3","_0_0_0_0_0_0_0_0_8_0_4","_0_0_0_0_0_0_0_0_9","_0_0_0_0_0_0_0_0_9_0","_0_0_0_0_0_0_0_0_9_0_0","_0_0_0_0_0_0_0_0_9_0_1","_0_0_0_0_0_0_0_0_9_0_2","_0_0_0_0_0_0_0_0_9_0_3","_0_0_0_0_0_0_0_0_9_0_4","_0_0_0_0_0_0_0_0_9_0_5","_0_0_0_0_0_0_0_0_9_0_6","_0_0_0_0_0_0_0_0_9_0_7","_0_0_0_0_0_0_0_0_9_0_8","_0_0_0_0_0_0_0_0_10","_0_0_0_0_0_0_1","_0_0_0_0_0_0_2","_0_0_0_0_0_0_3","_0_0_0_0_0_0_3_0","_0_0_0_0_0_0_3_0_0","_0_0_0_0_0_0_3_0_1","_0_0_0_0_0_0_4","_0_0_0_0_0_0_4_0","_0_0_0_0_0_0_4_0_0","_0_0_0_0_0_0_5","_0_0_0_0_0_0_5_0","_0_0_0_0_0_0_5_0_0","_0_0_0_0_0_0_6","_0_0_1","_0_0_1_0","_0_0_1_0_0","_0_0_1_0_1","_0_0_1_0_2","_0_0_2","_0_0_2_0","_0_0_2_0_0","_0_0_2_0_1","_0_0_2_0_2","_0_0_2_0_3","_0_0_2_0_4","_0_0_2_0_5","_0_0_2_0_6","_0_0_2_0_7"];const delta_x = 22; const delta_y = 30;
